from pathlib import Path
from collections import Counter
root=Path('shaders/escape_time_family/mandelbrot_variants')
counts=Counter()
files={}
for p in sorted(root.rglob('*.frag')):
    for line in p.read_text(errors='replace').splitlines():
        s=line.strip()
        if s.startswith(('vec2 ', 'vec3 ', 'float ', 'int ', 'bool ')) and '(' in s and ')' in s and not s.startswith('uniform '):
            name=s.split('(')[0].split()[-1]
            counts[name]+=1
            files.setdefault(name,[]).append(str(p))
for name,count in sorted(counts.items()):
    if count>1:
        print(name, count)
        for p in files[name]: print(' ',p)
